// Get raw AI output
const rawOutput = $json.output;

// Safety fallback
if (!rawOutput || typeof rawOutput !== 'string') {
  return {
    json: {
      instagram_caption: ''
    }
  };
}

let parsed;

// Safely parse JSON string
try {
  parsed = JSON.parse(rawOutput);
} catch (err) {
  return {
    json: {
      instagram_caption: ''
    }
  };
}

// Ensure correct structure
return {
  json: {
    instagram_caption:
      typeof parsed.instagram_caption === 'string'
        ? parsed.instagram_caption
        : ''
  }
};

// Get raw AI output
const rawOutput = $json.output;

// Fallback if output is missing or invalid
if (!rawOutput || typeof rawOutput !== 'string') {
  return {
    json: {
      email_subject: '',
      email_body: ''
    }
  };
}

let parsed;

// Safely parse JSON string
try {
  parsed = JSON.parse(rawOutput);
} catch (err) {
  return {
    json: {
      email_subject: '',
      email_body: ''
    }
  };
}

// Extract fields safely
return {
  json: {
    email_subject:
      parsed.email_newsletter?.subject && typeof parsed.email_newsletter.subject === 'string'
        ? parsed.email_newsletter.subject
        : '',

    email_body:
      parsed.email_newsletter?.body && typeof parsed.email_newsletter.body === 'string'
        ? parsed.email_newsletter.body
        : ''
  }
};

// Get raw AI output (JSON string)
const rawOutput = $json.output;

// Fallback if output is missing or invalid
if (!rawOutput || typeof rawOutput !== 'string') {
  return {
    json: {
      key_takeaways: '',
      key_takeaways_list: []
    }
  };
}

let parsed;

// Safely parse JSON string
try {
  parsed = JSON.parse(rawOutput);
} catch (err) {
  return {
    json: {
      key_takeaways: '',
      key_takeaways_list: []
    }
  };
}

// Normalize key_takeaways
const takeawaysArray = Array.isArray(parsed.key_takeaways)
  ? parsed.key_takeaways
  : [];

// Return both array + string versions (useful for Sheets, Notion, DBs)
return {
  json: {
    key_takeaways_list: takeawaysArray,
    key_takeaways: takeawaysArray.join(' | ')
  }
};

